1	// Package api implements the client-side API for code wishing to interact
2	// with the ollama service. The methods of the [Client] type correspond to
3	// the ollama REST API as described in [the API documentation].
4	// The ollama command-line client itself uses this package to interact with
5	// the backend service.
6	//
7	// # Examples
8	//
9	// Several examples of using this package are available [in the GitHub
10	// repository].
11	//
12	// [the API documentation]: https://github.com/ollama/ollama/blob/main/docs/api.md
13	// [in the GitHub repository]: https://github.com/ollama/ollama/tree/main/api/examples
14	package api
15	
16	import (
17		"bufio"
18		"bytes"
19		"context"
20		"encoding/json"
21		"errors"
22		"fmt"
23		"io"
24		"net/http"
25		"net/url"
26		"runtime"
27		"strconv"
28		"time"
29	
30		"github.com/ollama/ollama/auth"
31		"github.com/ollama/ollama/envconfig"
32		"github.com/ollama/ollama/format"
33		"github.com/ollama/ollama/version"
34	)
35	
36	// Client encapsulates client state for interacting with the ollama
37	// service. Use [ClientFromEnvironment] to create new Clients.
38	type Client struct {
39		base *url.URL
40		http *http.Client
41	}
42	
43	func checkError(resp *http.Response, body []byte) error {
44		if resp.StatusCode < http.StatusBadRequest {
45			return nil
46		}
47	
48		if resp.StatusCode == http.StatusUnauthorized {
49			authError := AuthorizationError{StatusCode: resp.StatusCode}
50			json.Unmarshal(body, &authError)
51			return authError
52		}
53	
54		apiError := StatusError{StatusCode: resp.StatusCode}
55	
56		err := json.Unmarshal(body, &apiError)
57		if err != nil {
58			// Use the full body as the message if we fail to decode a response.
59			apiError.ErrorMessage = string(body)
60		}
61	
62		return apiError
63	}
64	
65	// ClientFromEnvironment creates a new [Client] using configuration from the
66	// environment variable OLLAMA_HOST, which points to the network host and
67	// port on which the ollama service is listening. The format of this variable
68	// is:
69	//
70	//	<scheme>://<host>:<port>
71	//
72	// If the variable is not specified, a default ollama host and port will be
73	// used.
74	func ClientFromEnvironment() (*Client, error) {
75		return &Client{
76			base: envconfig.Host(),
77			http: http.DefaultClient,
78		}, nil
79	}
80	
81	func NewClient(base *url.URL, http *http.Client) *Client {
82		return &Client{
83			base: base,
84			http: http,
85		}
86	}
87	
88	func getAuthorizationToken(ctx context.Context, challenge string) (string, error) {
89		token, err := auth.Sign(ctx, []byte(challenge))
90		if err != nil {
91			return "", err
92		}
93		return token, nil
94	}
95	
96	func (c *Client) do(ctx context.Context, method, path string, reqData, respData any) error {
97		var reqBody io.Reader
98		var data []byte
99		var err error
100	
101		switch reqData := reqData.(type) {
102		case io.Reader:
103			// reqData is already an io.Reader
104			reqBody = reqData
105		case nil:
106			// noop
107		default:
108			data, err = json.Marshal(reqData)
109			if err != nil {
110				return err
111			}
112	
113			reqBody = bytes.NewReader(data)
114		}
115	
116		requestURL := c.base.JoinPath(path)
117	
118		var token string
119		if envconfig.UseAuth() || c.base.Hostname() == "ollama.com" {
120			now := strconv.FormatInt(time.Now().Unix(), 10)
121			chal := fmt.Sprintf("%s,%s?ts=%s", method, path, now)
122			token, err = getAuthorizationToken(ctx, chal)
123			if err != nil {
124				return err
125			}
126	
127			q := requestURL.Query()
128			q.Set("ts", now)
129			requestURL.RawQuery = q.Encode()
130		}
131	
132		request, err := http.NewRequestWithContext(ctx, method, requestURL.String(), reqBody)
133		if err != nil {
134			return err
135		}
136	
137		request.Header.Set("Content-Type", "application/json")
138		request.Header.Set("Accept", "application/json")
139		request.Header.Set("User-Agent", fmt.Sprintf("ollama/%s (%s %s) Go/%s", version.Version, runtime.GOARCH, runtime.GOOS, runtime.Version()))
140	
141		if token != "" {
142			request.Header.Set("Authorization", token)
143		}
144	
145		respObj, err := c.http.Do(request)
146		if err != nil {
147			return err
148		}
149		defer respObj.Body.Close()
150	
151		respBody, err := io.ReadAll(respObj.Body)
152		if err != nil {
153			return err
154		}
155	
156		if err := checkError(respObj, respBody); err != nil {
157			return err
158		}
159	
160		if len(respBody) > 0 && respData != nil {
161			if err := json.Unmarshal(respBody, respData); err != nil {
162				return err
163			}
164		}
165		return nil
166	}
167	
168	const maxBufferSize = 8 * format.MegaByte
169	
170	func (c *Client) stream(ctx context.Context, method, path string, data any, fn func([]byte) error) error {
171		var buf io.Reader
172		if data != nil {
173			bts, err := json.Marshal(data)
174			if err != nil {
175				return err
176			}
177	
178			buf = bytes.NewBuffer(bts)
179		}
180	
181		requestURL := c.base.JoinPath(path)
182	
183		var token string
184		if envconfig.UseAuth() || c.base.Hostname() == "ollama.com" {
185			var err error
186			now := strconv.FormatInt(time.Now().Unix(), 10)
187			chal := fmt.Sprintf("%s,%s?ts=%s", method, path, now)
188			token, err = getAuthorizationToken(ctx, chal)
189			if err != nil {
190				return err
191			}
192	
193			q := requestURL.Query()
194			q.Set("ts", now)
195			requestURL.RawQuery = q.Encode()
196		}
197	
198		request, err := http.NewRequestWithContext(ctx, method, requestURL.String(), buf)
199		if err != nil {
200			return err
201		}
202	
203		request.Header.Set("Content-Type", "application/json")
204		request.Header.Set("Accept", "application/x-ndjson")
205		request.Header.Set("User-Agent", fmt.Sprintf("ollama/%s (%s %s) Go/%s", version.Version, runtime.GOARCH, runtime.GOOS, runtime.Version()))
206	
207		if token != "" {
208			request.Header.Set("Authorization", token)
209		}
210	
211		response, err := c.http.Do(request)
212		if err != nil {
213			return err
214		}
215		defer response.Body.Close()
216	
217		scanner := bufio.NewScanner(response.Body)
218		// increase the buffer size to avoid running out of space
219		scanBuf := make([]byte, 0, maxBufferSize)
220		scanner.Buffer(scanBuf, maxBufferSize)
221		for scanner.Scan() {
222			var errorResponse struct {
223				Error     string `json:"error,omitempty"`
224				SigninURL string `json:"signin_url,omitempty"`
225			}
226	
227			bts := scanner.Bytes()
228			if err := json.Unmarshal(bts, &errorResponse); err != nil {
229				if response.StatusCode >= http.StatusBadRequest {
230					return StatusError{
231						StatusCode:   response.StatusCode,
232						Status:       response.Status,
233						ErrorMessage: string(bts),
234					}
235				}
236				return errors.New(string(bts))
237			}
238	
239			if response.StatusCode == http.StatusUnauthorized {
240				return AuthorizationError{
241					StatusCode: response.StatusCode,
242					Status:     response.Status,
243					SigninURL:  errorResponse.SigninURL,
244				}
245			} else if response.StatusCode >= http.StatusBadRequest {
246				return StatusError{
247					StatusCode:   response.StatusCode,
248					Status:       response.Status,
249					ErrorMessage: errorResponse.Error,
250				}
251			}
252	
253			if errorResponse.Error != "" {
254				return errors.New(errorResponse.Error)
255			}
256	
257			if err := fn(bts); err != nil {
258				return err
259			}
260		}
261	
262		return nil
263	}
264	
265	// GenerateResponseFunc is a function that [Client.Generate] invokes every time
266	// a response is received from the service. If this function returns an error,
267	// [Client.Generate] will stop generating and return this error.
268	type GenerateResponseFunc func(GenerateResponse) error
269	
270	// Generate generates a response for a given prompt. The req parameter should
271	// be populated with prompt details. fn is called for each response (there may
272	// be multiple responses, e.g. in case streaming is enabled).
273	func (c *Client) Generate(ctx context.Context, req *GenerateRequest, fn GenerateResponseFunc) error {
274		return c.stream(ctx, http.MethodPost, "/api/generate", req, func(bts []byte) error {
275			var resp GenerateResponse
276			if err := json.Unmarshal(bts, &resp); err != nil {
277				return err
278			}
279	
280			return fn(resp)
281		})
282	}
283	
284	// ChatResponseFunc is a function that [Client.Chat] invokes every time
285	// a response is received from the service. If this function returns an error,
286	// [Client.Chat] will stop generating and return this error.
287	type ChatResponseFunc func(ChatResponse) error
288	
289	// Chat generates the next message in a chat. [ChatRequest] may contain a
290	// sequence of messages which can be used to maintain chat history with a model.
291	// fn is called for each response (there may be multiple responses, e.g. if case
292	// streaming is enabled).
293	func (c *Client) Chat(ctx context.Context, req *ChatRequest, fn ChatResponseFunc) error {
294		return c.stream(ctx, http.MethodPost, "/api/chat", req, func(bts []byte) error {
295			var resp ChatResponse
296			if err := json.Unmarshal(bts, &resp); err != nil {
297				return err
298			}
299	
300			return fn(resp)
301		})
302	}
303	
304	// PullProgressFunc is a function that [Client.Pull] invokes every time there
305	// is progress with a "pull" request sent to the service. If this function
306	// returns an error, [Client.Pull] will stop the process and return this error.
307	type PullProgressFunc func(ProgressResponse) error
308	
309	// Pull downloads a model from the ollama library. fn is called each time
310	// progress is made on the request and can be used to display a progress bar,
311	// etc.
312	func (c *Client) Pull(ctx context.Context, req *PullRequest, fn PullProgressFunc) error {
313		return c.stream(ctx, http.MethodPost, "/api/pull", req, func(bts []byte) error {
314			var resp ProgressResponse
315			if err := json.Unmarshal(bts, &resp); err != nil {
316				return err
317			}
318	
319			return fn(resp)
320		})
321	}
322	
323	// PushProgressFunc is a function that [Client.Push] invokes when progress is
324	// made.
325	// It's similar to other progress function types like [PullProgressFunc].
326	type PushProgressFunc func(ProgressResponse) error
327	
328	// Push uploads a model to the model library; requires registering for ollama.ai
329	// and adding a public key first. fn is called each time progress is made on
330	// the request and can be used to display a progress bar, etc.
331	func (c *Client) Push(ctx context.Context, req *PushRequest, fn PushProgressFunc) error {
332		return c.stream(ctx, http.MethodPost, "/api/push", req, func(bts []byte) error {
333			var resp ProgressResponse
334			if err := json.Unmarshal(bts, &resp); err != nil {
335				return err
336			}
337	
338			return fn(resp)
339		})
340	}
341	
342	// CreateProgressFunc is a function that [Client.Create] invokes when progress
343	// is made.
344	// It's similar to other progress function types like [PullProgressFunc].
345	type CreateProgressFunc func(ProgressResponse) error
346	
347	// Create creates a model from a [Modelfile]. fn is a progress function that
348	// behaves similarly to other methods (see [Client.Pull]).
349	//
350	// [Modelfile]: https://github.com/ollama/ollama/blob/main/docs/modelfile.mdx
351	func (c *Client) Create(ctx context.Context, req *CreateRequest, fn CreateProgressFunc) error {
352		return c.stream(ctx, http.MethodPost, "/api/create", req, func(bts []byte) error {
353			var resp ProgressResponse
354			if err := json.Unmarshal(bts, &resp); err != nil {
355				return err
356			}
357	
358			return fn(resp)
359		})
360	}
361	
362	// List lists models that are available locally.
363	func (c *Client) List(ctx context.Context) (*ListResponse, error) {
364		var lr ListResponse
365		if err := c.do(ctx, http.MethodGet, "/api/tags", nil, &lr); err != nil {
366			return nil, err
367		}
368		return &lr, nil
369	}
370	
371	// ListRunning lists running models.
372	func (c *Client) ListRunning(ctx context.Context) (*ProcessResponse, error) {
373		var lr ProcessResponse
374		if err := c.do(ctx, http.MethodGet, "/api/ps", nil, &lr); err != nil {
375			return nil, err
376		}
377		return &lr, nil
378	}
379	
380	// Copy copies a model - creating a model with another name from an existing
381	// model.
382	func (c *Client) Copy(ctx context.Context, req *CopyRequest) error {
383		if err := c.do(ctx, http.MethodPost, "/api/copy", req, nil); err != nil {
384			return err
385		}
386		return nil
387	}
388	
389	// Delete deletes a model and its data.
390	func (c *Client) Delete(ctx context.Context, req *DeleteRequest) error {
391		if err := c.do(ctx, http.MethodDelete, "/api/delete", req, nil); err != nil {
392			return err
393		}
394		return nil
395	}
396	
397	// Show obtains model information, including details, modelfile, license etc.
398	func (c *Client) Show(ctx context.Context, req *ShowRequest) (*ShowResponse, error) {
399		var resp ShowResponse
400		if err := c.do(ctx, http.MethodPost, "/api/show", req, &resp); err != nil {
401			return nil, err
402		}
403		return &resp, nil
404	}
405	
406	// Heartbeat checks if the server has started and is responsive; if yes, it
407	// returns nil, otherwise an error.
408	func (c *Client) Heartbeat(ctx context.Context) error {
409		if err := c.do(ctx, http.MethodHead, "/", nil, nil); err != nil {
410			return err
411		}
412		return nil
413	}
414	
415	// Embed generates embeddings from a model.
416	func (c *Client) Embed(ctx context.Context, req *EmbedRequest) (*EmbedResponse, error) {
417		var resp EmbedResponse
418		if err := c.do(ctx, http.MethodPost, "/api/embed", req, &resp); err != nil {
419			return nil, err
420		}
421		return &resp, nil
422	}
423	
424	// Embeddings generates an embedding from a model.
425	func (c *Client) Embeddings(ctx context.Context, req *EmbeddingRequest) (*EmbeddingResponse, error) {
426		var resp EmbeddingResponse
427		if err := c.do(ctx, http.MethodPost, "/api/embeddings", req, &resp); err != nil {
428			return nil, err
429		}
430		return &resp, nil
431	}
432	
433	// CreateBlob creates a blob from a file on the server. digest is the
434	// expected SHA256 digest of the file, and r represents the file.
435	func (c *Client) CreateBlob(ctx context.Context, digest string, r io.Reader) error {
436		return c.do(ctx, http.MethodPost, fmt.Sprintf("/api/blobs/%s", digest), r, nil)
437	}
438	
439	// Version returns the Ollama server version as a string.
440	func (c *Client) Version(ctx context.Context) (string, error) {
441		var version struct {
442			Version string `json:"version"`
443		}
444	
445		if err := c.do(ctx, http.MethodGet, "/api/version", nil, &version); err != nil {
446			return "", err
447		}
448	
449		return version.Version, nil
450	}
451	
452	// CloudStatusExperimental returns whether cloud features are disabled on the server.
453	func (c *Client) CloudStatusExperimental(ctx context.Context) (*StatusResponse, error) {
454		var status StatusResponse
455		if err := c.do(ctx, http.MethodGet, "/api/status", nil, &status); err != nil {
456			return nil, err
457		}
458	
459		return &status, nil
460	}
461	
462	// Signout will signout a client for a local ollama server.
463	func (c *Client) Signout(ctx context.Context) error {
464		return c.do(ctx, http.MethodPost, "/api/signout", nil, nil)
465	}
466	
467	// Disconnect will disconnect an ollama instance from ollama.com.
468	func (c *Client) Disconnect(ctx context.Context, encodedKey string) error {
469		return c.do(ctx, http.MethodDelete, fmt.Sprintf("/api/user/keys/%s", encodedKey), nil, nil)
470	}
471	
472	func (c *Client) Whoami(ctx context.Context) (*UserResponse, error) {
473		var resp UserResponse
474		if err := c.do(ctx, http.MethodPost, "/api/me", nil, &resp); err != nil {
475			return nil, err
476		}
477		return &resp, nil
478	}
